import{_ as e,c as t,o as s,a as n}from"./app.80007782.js";const m=JSON.parse('{"title":"\u{1F3DB}\uFE0F Academic Structure Module","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F31F} Key Features","slug":"\u{1F31F}-key-features","link":"#\u{1F31F}-key-features","children":[{"level":3,"title":"Comprehensive Institution Modeling","slug":"comprehensive-institution-modeling","link":"#comprehensive-institution-modeling","children":[]},{"level":3,"title":"Flexible Hierarchy Configuration","slug":"flexible-hierarchy-configuration","link":"#flexible-hierarchy-configuration","children":[]},{"level":3,"title":"Multi-Institution Support","slug":"multi-institution-support","link":"#multi-institution-support","children":[]}]},{"level":2,"title":"\u{1F4A1} Use Cases","slug":"\u{1F4A1}-use-cases","link":"#\u{1F4A1}-use-cases","children":[{"level":3,"title":"University Structure Example","slug":"university-structure-example","link":"#university-structure-example","children":[]},{"level":3,"title":"School Structure Example","slug":"school-structure-example","link":"#school-structure-example","children":[]}]},{"level":2,"title":"\u{1F527} Administration Tools","slug":"\u{1F527}-administration-tools","link":"#\u{1F527}-administration-tools","children":[{"level":3,"title":"Structure Management Interface","slug":"structure-management-interface","link":"#structure-management-interface","children":[]},{"level":3,"title":"Academic Year Configuration","slug":"academic-year-configuration","link":"#academic-year-configuration","children":[]}]},{"level":2,"title":"\u{1F4CB} Data Model","slug":"\u{1F4CB}-data-model","link":"#\u{1F4CB}-data-model","children":[]},{"level":2,"title":"\u{1F504} Integration Points","slug":"\u{1F504}-integration-points","link":"#\u{1F504}-integration-points","children":[]},{"level":2,"title":"\u{1F680} Getting Started","slug":"\u{1F680}-getting-started","link":"#\u{1F680}-getting-started","children":[]}],"relativePath":"en/modules/academic-structure-module.md","lastUpdated":1744659307000}'),a={name:"en/modules/academic-structure-module.md"},i=n(`<h1 id="\u{1F3DB}\uFE0F-academic-structure-module" tabindex="-1">\u{1F3DB}\uFE0F Academic Structure Module <a class="header-anchor" href="#\u{1F3DB}\uFE0F-academic-structure-module" aria-hidden="true">#</a></h1><p>The Academic Structure module serves as the backbone of UniTrack, modeling the organizational hierarchy of educational institutions with flexibility to accommodate various types of academic organizations.</p><h2 id="\u{1F31F}-key-features" tabindex="-1">\u{1F31F} Key Features <a class="header-anchor" href="#\u{1F31F}-key-features" aria-hidden="true">#</a></h2><h3 id="comprehensive-institution-modeling" tabindex="-1">Comprehensive Institution Modeling <a class="header-anchor" href="#comprehensive-institution-modeling" aria-hidden="true">#</a></h3><p>UniTrack can represent the full hierarchy of academic institutions:</p><ul><li><strong>Multiple institution types</strong>: Universities, colleges, schools, and specialized educational centers</li><li><strong>Organizational units</strong>: Faculties, departments, divisions, and specialized centers</li><li><strong>Academic programs</strong>: Degrees, majors, specializations, and certificates</li><li><strong>Course management</strong>: Subjects, classes, sections, and scheduling</li></ul><p><img src="https://via.placeholder.com/800x500?text=Academic+Structure+Diagram" alt="Academic Structure"></p><h3 id="flexible-hierarchy-configuration" tabindex="-1">Flexible Hierarchy Configuration <a class="header-anchor" href="#flexible-hierarchy-configuration" aria-hidden="true">#</a></h3><p>The system adapts to different educational structures worldwide:</p><ul><li><strong>Higher education model</strong>: Universities with faculties, departments, and programs</li><li><strong>K-12 model</strong>: Schools with grade levels, homerooms, and subject areas</li><li><strong>Mixed institutions</strong>: Organizations that combine multiple educational levels</li><li><strong>Custom structures</strong>: Ability to define unique organizational models</li></ul><h3 id="multi-institution-support" tabindex="-1">Multi-Institution Support <a class="header-anchor" href="#multi-institution-support" aria-hidden="true">#</a></h3><p>UniTrack is designed for educational ecosystems with multiple connected institutions:</p><ul><li><strong>Centralized management</strong>: Administer multiple institutions from a single platform</li><li><strong>Cross-institution visibility</strong>: Track student progression across educational levels</li><li><strong>Shared resources</strong>: Allow institutions to share faculty, facilities, and educational content</li><li><strong>Unified reporting</strong>: Generate reports across the entire educational network</li></ul><h2 id="\u{1F4A1}-use-cases" tabindex="-1">\u{1F4A1} Use Cases <a class="header-anchor" href="#\u{1F4A1}-use-cases" aria-hidden="true">#</a></h2><h3 id="university-structure-example" tabindex="-1">University Structure Example <a class="header-anchor" href="#university-structure-example" aria-hidden="true">#</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">University</span></span>
<span class="line"><span style="color:#A6ACCD;">\u251C\u2500\u2500 Faculty of Science</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Department of Physics</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2502   \u251C\u2500\u2500 Bachelor&#39;s in Physics</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2502   \u251C\u2500\u2500 Master&#39;s in Applied Physics</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2502   \u2514\u2500\u2500 PhD in Theoretical Physics</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Department of Mathematics</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2514\u2500\u2500 Department of Computer Science</span></span>
<span class="line"><span style="color:#A6ACCD;">\u251C\u2500\u2500 Faculty of Arts</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Department of History</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Department of Languages</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2514\u2500\u2500 Department of Fine Arts</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2514\u2500\u2500 Faculty of Medicine</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 Department of General Medicine</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 Department of Surgery</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2514\u2500\u2500 Department of Pharmacy</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h3 id="school-structure-example" tabindex="-1">School Structure Example <a class="header-anchor" href="#school-structure-example" aria-hidden="true">#</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">School</span></span>
<span class="line"><span style="color:#A6ACCD;">\u251C\u2500\u2500 Elementary Division</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 First Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Second Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2514\u2500\u2500 Third Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u251C\u2500\u2500 Middle School Division</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Fourth Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u251C\u2500\u2500 Fifth Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2502   \u2514\u2500\u2500 Sixth Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">\u2514\u2500\u2500 High School Division</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 Seventh Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 Eighth Grade</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2514\u2500\u2500 Ninth Grade</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h2 id="\u{1F527}-administration-tools" tabindex="-1">\u{1F527} Administration Tools <a class="header-anchor" href="#\u{1F527}-administration-tools" aria-hidden="true">#</a></h2><h3 id="structure-management-interface" tabindex="-1">Structure Management Interface <a class="header-anchor" href="#structure-management-interface" aria-hidden="true">#</a></h3><p>The module provides intuitive interfaces for:</p><ul><li><strong>Visual Hierarchy Editor</strong>: Drag-and-drop interface for creating and modifying the organizational structure</li><li><strong>Bulk Operations</strong>: Tools for creating multiple units, courses, or sections at once</li><li><strong>Templates</strong>: Pre-defined structural models for common educational institutions</li><li><strong>Import/Export</strong>: Transfer organizational structures between instances or from external systems</li></ul><p><img src="https://via.placeholder.com/800x400?text=Structure+Editor+Interface" alt="Structure Editor"></p><h3 id="academic-year-configuration" tabindex="-1">Academic Year Configuration <a class="header-anchor" href="#academic-year-configuration" aria-hidden="true">#</a></h3><p>Manage the academic calendar with:</p><ul><li><strong>Multiple calendar systems</strong>: Support for semester, trimester, quarter, and custom term structures</li><li><strong>Academic year definition</strong>: Set start and end dates for academic periods</li><li><strong>Holiday and break management</strong>: Define non-instructional days</li><li><strong>Schedule generation</strong>: Create course schedules based on academic periods</li></ul><h2 id="\u{1F4CB}-data-model" tabindex="-1">\u{1F4CB} Data Model <a class="header-anchor" href="#\u{1F4CB}-data-model" aria-hidden="true">#</a></h2><p>The Academic Structure module is built on a flexible data model:</p><ul><li><strong>Institution</strong>: The top-level entity representing an educational organization <ul><li><strong>Faculties/Schools/Divisions</strong>: Major organizational units within the institution <ul><li><strong>Departments</strong>: Subject-specific units containing programs and faculty <ul><li><strong>Programs/Majors</strong>: Structured educational pathways leading to degrees or certificates <ul><li><strong>Courses/Subjects</strong>: Individual educational components that make up a program <ul><li><strong>Classes/Sections</strong>: Specific instances of courses taught at particular times</li></ul></li></ul></li></ul></li></ul></li></ul></li></ul><p>Each entity in the hierarchy supports:</p><ul><li>Custom fields for institution-specific data</li><li>Flexible relationships between entities</li><li>Historical versioning for tracking changes over time</li><li>Metadata for accreditation and regulatory requirements</li></ul><h2 id="\u{1F504}-integration-points" tabindex="-1">\u{1F504} Integration Points <a class="header-anchor" href="#\u{1F504}-integration-points" aria-hidden="true">#</a></h2><p>The Academic Structure module connects with:</p><ul><li><strong>User Management</strong>: Associates users with positions in the academic structure</li><li><strong>Enrollment Management</strong>: Links students to programs, majors, and courses</li><li><strong>Scheduling System</strong>: Uses the structure to generate and manage timetables</li><li><strong>Reporting Engine</strong>: Provides organizational context for academic analytics</li><li><strong>Permission System</strong>: Bases access controls on position within the structure</li></ul><h2 id="\u{1F680}-getting-started" tabindex="-1">\u{1F680} Getting Started <a class="header-anchor" href="#\u{1F680}-getting-started" aria-hidden="true">#</a></h2><p>To set up your academic structure:</p><ol><li><strong>Define your institution type</strong>: Select the appropriate model (university, college, school)</li><li><strong>Create top-level divisions</strong>: Add faculties, schools, or divisions</li><li><strong>Build departments</strong>: Create subject-specific organizational units</li><li><strong>Add programs and majors</strong>: Define the educational pathways</li><li><strong>Create courses</strong>: Set up individual subjects with their requirements and details</li><li><strong>Organize classes</strong>: Schedule specific course instances</li></ol><p>The Academic Structure module provides the foundation for all other UniTrack functions, ensuring that the system accurately reflects your institution&#39;s organization and educational offerings.</p>`,38),r=[i];function l(o,c,u,d,p,h){return s(),t("div",null,r)}const f=e(a,[["render",l]]);export{m as __pageData,f as default};
